#!/usr/bin/env python3
import json, subprocess, sys

SAS = "/opt/homebrew/bin/SwitchAudioSource"
query = (sys.argv[1] if len(sys.argv) > 1 else "").strip().lower()

try:
    cur = subprocess.check_output([SAS, "-c", "-t", "output", "-f", "json"], text=True).strip()
    current_uid = json.loads(cur).get("uid", "")
except Exception:
    current_uid = ""

devices = []
try:
    out = subprocess.check_output([SAS, "-a", "-t", "output", "-f", "json"], text=True)
    for line in out.splitlines():
        line = line.strip()
        if line:
            devices.append(json.loads(line))
except Exception:
    devices = []

items = []
for d in devices:
    name = d.get("name", "")
    uid = d.get("uid", "")
    if query and query not in name.lower():
        continue
    is_cur = (uid == current_uid)
    items.append({
        "title": ("✓ " + name) if is_cur else name,
        "subtitle": "現在の出力先" if is_cur else "この出力先に切り替え",
        "arg": uid,
        "valid": (not is_cur),
        "variables": {"uid": uid, "device_name": name},
    })

if not items:
    items = [{"title": "出力デバイスが見つかりません", "valid": False}]

print(json.dumps({"items": items}, ensure_ascii=False))
